# Show Generated Elixir Code
#
# This script displays the actual Elixir AST generated by GridCodec

IO.puts("=" |> String.duplicate(70))
IO.puts("GENERATED ELIXIR CODE ANALYSIS")
IO.puts("=" |> String.duplicate(70))

# Define a codec that captures the generated AST
defmodule ShowGeneratedCode do
  defmacro capture_defcodec(do: block) do
    # Parse the block to extract field definitions
    {fields, groups} = GridCodec.Compiler.parse_fields(block)

    # Get the schema
    {fixed_fields, var_fields, groups, _block_length} =
      GridCodec.Compiler.build_schema(fields, groups, :little)

    # Generate encoder AST
    encoder_ast = GridCodec.Compiler.generate_encoder_ast(fixed_fields, var_fields, groups, :little)

    # Generate decoder AST
    decoder_ast = GridCodec.Compiler.generate_decoder_ast(fixed_fields, var_fields, groups, :little)

    quote do
      def show_encoder_ast do
        unquote(Macro.escape(encoder_ast))
      end

      def show_decoder_ast do
        unquote(Macro.escape(decoder_ast))
      end

      def encoder_code do
        show_encoder_ast() |> Macro.to_string()
      end

      def decoder_code do
        show_decoder_ast() |> Macro.to_string()
      end
    end
  end
end

# We need to expose the internal functions from Compiler
# Let's just manually show what gets generated by examining a real codec

defmodule SimpleCodec do
  use GridCodec

  defcodec do
    field(:id, :u64)
    field(:count, :u32)
    field(:flag, :bool)
  end
end

defmodule VarCodec do
  use GridCodec

  defcodec do
    field(:id, :u64)
    field(:name, :string16)
    field(:description, :string32)
  end
end

defmodule GroupCodec do
  use GridCodec

  def encode_entry(%{id: id, value: v}), do: <<id::little-64, v::little-32>>
  def decode_entry(<<id::little-64, v::little-32>>), do: {:ok, %{id: id, value: v}}

  defcodec do
    field(:batch_id, :u64)

    group :items,
      entry_encoder: &GroupCodec.encode_entry/1,
      entry_decoder: &GroupCodec.decode_entry/1 do
      field(:id, :u64)
      field(:value, :u32)
    end
  end
end

IO.puts("\n" <> String.duplicate("-", 70))
IO.puts("1. SIMPLE CODEC (fixed fields only)")
IO.puts(String.duplicate("-", 70))

IO.puts("\nSchema:")
schema = SimpleCodec.__schema__()
IO.inspect(schema.fixed_fields, label: "Fixed fields")
IO.inspect(schema.var_fields, label: "Var fields")
IO.puts("Block length: #{schema.block_length} bytes")

# Show the encode function source by decompiling
IO.puts("\nEncode behavior (via timing test):")
data = %{id: 12345, count: 100, flag: true}
binary = SimpleCodec.encode(data)
IO.puts("  Input: #{inspect(data)}")
IO.puts("  Output: #{inspect(binary, limit: 50)}")
IO.puts("  Size: #{byte_size(binary)} bytes")

IO.puts("\n" <> String.duplicate("-", 70))
IO.puts("2. VAR CODEC (with string fields)")
IO.puts(String.duplicate("-", 70))

IO.puts("\nSchema:")
schema = VarCodec.__schema__()
IO.inspect(schema.fixed_fields, label: "Fixed fields")
IO.inspect(schema.var_fields, label: "Var fields")
IO.puts("Block length: #{schema.block_length} bytes")

IO.puts("\nEncode behavior:")
data = %{id: 12345, name: "Hello", description: "A longer description here"}
binary = VarCodec.encode(data)
IO.puts("  Input: #{inspect(data)}")
IO.puts("  Output size: #{byte_size(binary)} bytes")
IO.puts("  Output hex: #{binary |> :binary.bin_to_list() |> Enum.map(&Integer.to_string(&1, 16)) |> Enum.join(" ")}")

IO.puts("\n" <> String.duplicate("-", 70))
IO.puts("3. GROUP CODEC")
IO.puts(String.duplicate("-", 70))

IO.puts("\nSchema:")
schema = GroupCodec.__schema__()
IO.inspect(schema.fixed_fields, label: "Fixed fields")
IO.inspect(schema.groups, label: "Groups")

IO.puts("\nEncode behavior:")
data = %{batch_id: 999, items: [%{id: 1, value: 10}, %{id: 2, value: 20}]}
binary = GroupCodec.encode(data)
IO.puts("  Input: #{inspect(data)}")
IO.puts("  Output size: #{byte_size(binary)} bytes")

IO.puts("\n" <> String.duplicate("-", 70))
IO.puts("4. EXAMINING THE COMPILER SOURCE")
IO.puts(String.duplicate("-", 70))

# Show the actual encode_ast generation for U64
IO.puts("\nU64.encode_ast generates:")
IO.puts("""
  quote do
    case Map.get(data_var, field_name, default) do
      nil -> null_val
      v -> v
    end :: unsigned-little-64
  end
""")

IO.puts("\nBool.encode_ast generates:")
IO.puts("""
  quote do
    case Map.get(data_var, field_name, default) do
      true -> 1
      false -> 0
      _ -> 255
    end :: 8
  end
""")

IO.puts("\nString.encode16 does:")
IO.puts("""
  def encode16(nil), do: <<0::little-16>>
  def encode16(str) when is_binary(str) do
    len = byte_size(str)
    <<len::little-16, str::binary>>
  end
""")

IO.puts("\n" <> String.duplicate("-", 70))
IO.puts("5. VAR ENCODER PATH")
IO.puts(String.duplicate("-", 70))

IO.puts("\nThe var encoder generates:")
IO.puts("""
  quote do
    IO.iodata_to_binary([
      (value = Map.get(data, :name); GridCodec.Types.String.encode16(value)),
      (value = Map.get(data, :description); GridCodec.Types.String.encode32(value))
    ])
  end
""")

IO.puts("\nThis creates intermediate binaries! Each encode16/encode32 creates a binary,")
IO.puts("then they're combined via IO.iodata_to_binary.")

IO.puts("\n" <> String.duplicate("-", 70))
IO.puts("6. GROUP ENCODER PATH")
IO.puts(String.duplicate("-", 70))

IO.puts("\nThe group encoder generates:")
IO.puts("""
  quote do
    IO.iodata_to_binary([
      case Map.get(data, :items) do
        entries when is_list(entries) ->
          encoded_entries = Enum.map(entries, entry_encoder)
          GridCodec.Group.encode(encoded_entries, block_length)

        pre_encoded when is_binary(pre_encoded) ->
          pre_encoded

        _ ->
          <<0::little-16, 0::little-16>>  # Empty group header
      end
    ])
  end
""")

IO.puts("\n" <> String.duplicate("-", 70))
IO.puts("7. OPTIMIZATION OPPORTUNITIES IDENTIFIED")
IO.puts(String.duplicate("-", 70))

IO.puts("""

A. ENCODE PATH:
   1. Uses Map.get/3 (Elixir) instead of :maps.get/3 (BIF)
   2. Has redundant nil check: Map.get with default + case nil check
   3. Var fields use IO.iodata_to_binary with list of pre-built binaries

B. DECODE PATH:
   1. Already optimized - single bs_match
   2. Map.merge removed for empty groups/vars ✓

C. VAR STRING PATH:
   1. Each string field creates its own binary
   2. Then combined via IO.iodata_to_binary
   3. Could instead build a single binary with segments
""")
